fallback() external payable {
    address impl = ERC1967._getImplementation();
    if (impl == address(0)) impl = defaultImpl;
    (bool ok, bytes memory r) = impl.delegatecall(msg.data);
    if (!ok) assembly { revert(add(r, 32), mload(r)) }
    assembly { return(add(r, 32), mload(r)) }
}

yul_optimized:
fallback() external payable virtual {
    bytes32 implementation;
    assembly {
        mstore(0x40, returndatasize()) // Optimization: change `6080604052` runtime prelude into `3d604052`
        implementation := sload(_ERC1967_IMPLEMENTATION_SLOT)
    }
    if (implementation == bytes32(0)) {
        implementation = _defaultImplementation;
        assembly {
            // Lazy-initialize impl slot only on calldatasize == 0 (the 0-ETH-send trick)
            // Function selectors are 4 bytes so staticcalls won't accidentally trigger this.
            if iszero(calldatasize()) { sstore(_ERC1967_IMPLEMENTATION_SLOT, implementation) }
        }
    }
    assembly {
        calldatacopy(returndatasize(), returndatasize(), calldatasize())
        if iszero(delegatecall(gas(), implementation,
            returndatasize(), calldatasize(), codesize(), returndatasize())) {
            returndatacopy(0x00, 0x00, returndatasize())
            revert(0x00, returndatasize())
        }
        returndatacopy(0x00, 0x00, returndatasize())
        return(0x00, returndatasize())
    }
}
